#!/usr/bin/env python3
import json, os, math, collections, sys
sys.path.insert(1, '/app/task_file/scripts')
from cost_model import CostModel, align, HEADS, HIDDEN, CostConsts

GRAN=64
MAX_SHAPES=8
ROOT='/app/task_file'
IN1=f'{ROOT}/input_data/requests_bucket_1.jsonl'
IN2=f'{ROOT}/input_data/requests_bucket_2.jsonl'
OUT1=f'{ROOT}/output_data/plan_b1.jsonl'
OUT2=f'{ROOT}/output_data/plan_b2.jsonl'
TH={
 'b1': {'cost':3.0e11,'pad_ratio':0.055,'p95_latency_ms':2.1e6,'sequential_timecost':2.7e8},
 'b2': {'cost':4.8e10,'pad_ratio':0.15,'p95_latency_ms':2.1e5,'sequential_timecost':3.2e7},
}

def load(p):
    return [json.loads(l) for l in open(p)]

def uniq(reqs):
    seen=set(); out=[]
    for r in reqs:
        s=align(r['prompt_len'],GRAN)
        if s not in seen:
            seen.add(s); out.append(s)
    return sorted(out)

def quantile_reps(u,k):
    if not u or k<=0: return []
    if len(u)<=k: return u[:]
    out=set()
    for i in range(k):
        q=(i+0.5)/k
        idx=max(0,min(len(u)-1,int(q*(len(u)-1))))
        out.add(u[idx])
    out.add(u[-1])
    return sorted(out)

def endpoint_reps(u,k):
    if not u or k<=0: return []
    if len(u)<=k: return u[:]
    out=set()
    for i in range(k):
        idx=min(len(u)-1,int(round((i+1)*len(u)/k))-1)
        out.add(u[idx])
    return sorted(out)

def assign(s,reps):
    for r in reps:
        if r>=s: return r
    return reps[-1]

def build(reqs,reps,gmax,bsize):
    groups=collections.defaultdict(list)
    for r in reqs:
        groups[assign(align(r['prompt_len'],GRAN),reps)].append(r)
    recs=[]; bid=0
    for rep in sorted(groups):
        grp=sorted(groups[rep], key=lambda x:x['gen_len'])
        cur=[]; cmax=1
        for r in grp:
            g=r['gen_len']
            if cur and ((gmax and max(cmax,g)>gmax) or (bsize and len(cur)>=bsize)):
                bid+=1
                b=f'b-{bid:04d}'
                for x in cur:
                    recs.append({'request_id':x['request_id'],'batch_id':b,'shape':{'seq_align':rep,'heads_align':HEADS,'hidden_align':HIDDEN}})
                cur=[r]; cmax=g
            else:
                cur.append(r); cmax=max(cmax,g)
        if cur:
            bid+=1
            b=f'b-{bid:04d}'
            for x in cur:
                recs.append({'request_id':x['request_id'],'batch_id':b,'shape':{'seq_align':rep,'heads_align':HEADS,'hidden_align':HIDDEN}})
    return recs

def scalar_metrics(plan, req_map, cm):
    # Faster scalar-only metric calculation matching CostModel.plan_metrics.
    batches=collections.defaultdict(list)
    shape_of={}
    for p in plan:
        batches[p['batch_id']].append(req_map[p['request_id']])
        shape_of[p['batch_id']]=tuple(p['shape'][k] for k in ('seq_align','heads_align','hidden_align'))
    c=CostConsts()
    total_cost=0.0
    pad_tokens=0
    real_tokens=0
    lat_by_batch={}
    for bid, rs in batches.items():
        S_max=max(align(r['prompt_len'],GRAN) for r in rs)
        G_max=max(r['gen_len'] for r in rs)
        cost_prefill=sum(c.Kp_attn*(align(r['prompt_len'],GRAN)**2)+c.Kp_mlp*(align(r['prompt_len'],GRAN)*HIDDEN) for r in rs)
        a=S_max; n=G_max
        sum_sq=n*(a*a)+a*n*(n-1)+(n*(n-1)*(2*n-1))//6
        sum_lin=n*a+n*(n-1)/2
        cost_decode=len(rs)*(c.Kd_attn*sum_sq+c.Kd_mlp*HIDDEN*sum_lin)
        total_cost+=cost_prefill+cost_decode
        pad_tokens+=sum(align(r['prompt_len'],GRAN)-r['prompt_len'] for r in rs)+sum(G_max-r['gen_len'] for r in rs)
        real_tokens+=sum(r['prompt_len']+r['gen_len'] for r in rs)
        lat_prefill=[c.Tp_attn*(align(r['prompt_len'],GRAN)**2)+c.Tp_mlp*(align(r['prompt_len'],GRAN)*HIDDEN) for r in rs]
        lat_decode_per=c.Td_attn*sum_sq+c.Td_mlp*HIDDEN*sum_lin
        lat_by_batch[bid]=[lp+lat_decode_per+c.Tbatch_overhead_ms for lp in lat_prefill]
    unique_shapes=set(shape_of.values())
    for s,h,hid in unique_shapes:
        if s>0:
            total_cost+=c.Kshape_attn*(s**2)+c.Kshape_mlp*(s*HIDDEN)
    total_cost+=c.Kbatch_overhead_cost*len(batches)
    shape_batches=collections.defaultdict(list)
    for bid,shp in shape_of.items():
        shape_batches[shp].append(bid)
    all_lats=[]
    for shp in sorted(shape_batches):
        b_list=sorted(shape_batches[shp])
        lats=lat_by_batch[b_list[0]]
        if lats and c.Tshape_compile_ms>0:
            lats=lats[:]  # avoid mutating shared list
            lats[0]+=c.Tshape_compile_ms
        for bid in b_list:
            all_lats.extend(lat_by_batch[bid])
    seq=0.0
    for bid in sorted(lat_by_batch):
        if lat_by_batch[bid]:
            seq+=max(lat_by_batch[bid])
    arr=sorted(all_lats)
    p95=arr[max(0,min(len(arr)-1,int(math.ceil(0.95*len(arr)))-1))] if arr else 0.0
    return {
        'cost':total_cost,
        'pad_ratio':pad_tokens/max(1,real_tokens),
        'p95_latency_ms':p95,
        'sequential_timecost':seq,
    }

def ok(m,key):
    return all(m[k]<=TH[key][k] for k in TH[key])

def validate(plan, req_map):
    ids=[p['request_id'] for p in plan]
    shapes=set((p['shape']['seq_align'],p['shape']['heads_align'],p['shape']['hidden_align']) for p in plan)
    batch_shapes=collections.defaultdict(set)
    for p in plan:
        batch_shapes[p['batch_id']].add(p['shape']['seq_align'])
    return {
        'all_included': len(ids)==len(req_map)==len(set(ids)),
        'shapes_ok': len(shapes)<=MAX_SHAPES and all(s[1]==32 and s[2]==4096 and s[0]%GRAN==0 for s in shapes),
        'seq_ok': all(align(req_map[p['request_id']]['prompt_len'],GRAN)<=p['shape']['seq_align'] for p in plan),
        'batch_shape_consistent': all(len(v)==1 for v in batch_shapes.values()),
    }

def write(p, recs):
    os.makedirs(os.path.dirname(p), exist_ok=True)
    with open(p,'w') as f:
        for r in recs:
            f.write(json.dumps(r)+'\n')

def main():
    reqs1=load(IN1); reqs2=load(IN2)
    map1={r['request_id']:r for r in reqs1}; map2={r['request_id']:r for r in reqs2}
    u1=uniq(reqs1); u2=uniq(reqs2)
    cm=CostModel(GRAN)

    cands=[]
    for k1 in range(2,8):
        for k2 in range(1,9-k1):
            cands.append(sorted(set(quantile_reps(u1,k1)+quantile_reps(u2,k2))))
            cands.append(sorted(set(endpoint_reps(u1,k1)+endpoint_reps(u2,k2))))
    manual=[
        [64,128,448,832,1280,1792,2048],
        [64,128,320,640,1216,1664,2048],
        [64,128,384,704,1152,1600,2048],
        [64,128,448,960,1408,1792,2048],
        [64,128,576,1152,1600,2048],
        [64,256,576,1152,1600,2048],
        [64,192,448,768,1280,1792,2048],
        [64,128,512,1024,1536,2048],
    ]
    for m in manual:
        if len(m)<=MAX_SHAPES and all(x in u1 or x in u2 for x in m):
            cands.append(m)
    # Keep unique and valid enough
    seen=set(); cands2=[]
    for c in cands:
        if 1<=len(c)<=MAX_SHAPES:
            t=tuple(c)
            if t not in seen:
                seen.add(t); cands2.append(c)

    g1s=[24,32,40,48,56,64,80,96,112,128,144,160,192,224,256,320,384]
    s1s=[4,6,8,10,12,16,20,24,32,40,48,64,80,96,128]
    g2s=[16,20,24,28,32,40,48,56,64,72,80,96,112,128,144,160]
    s2s=[4,6,8,10,12,16,20,24,32,40,48,64,80,96]

    best=None
    for reps in cands2:
        # quick precheck: all assigned shapes must be in reps
        for g1 in g1s:
            for s1 in s1s:
                p1=build(reqs1,reps,g1,s1)
                m1=scalar_metrics(p1,map1,cm)
                # If bucket1 cost/pad hopeless, skip bucket2 search
                if m1['cost']>TH['b1']['cost']*1.5 or m1['pad_ratio']>TH['b1']['pad_ratio']*1.5 or m1['p95_latency_ms']>TH['b1']['p95_latency_ms']*1.5 or m1['sequential_timecost']>TH['b1']['sequential_timecost']*1.5:
                    continue
                for g2 in g2s:
                    for s2 in s2s:
                        p2=build(reqs2,reps,g2,s2)
                        shapes=set((x['shape']['seq_align'],x['shape']['heads_align'],x['shape']['hidden_align']) for x in p1+p2)
                        if len(shapes)>MAX_SHAPES:
                            continue
                        m2=scalar_metrics(p2,map2,cm)
                        score=m1['cost']+m2['cost']
                        if ok(m1,'b1') and ok(m2,'b2') and (best is None or score<best[0]):
                            best=(score,reps,g1,s1,g2,s2,p1,p2,m1,m2)
    if best:
        _,reps,g1,s1,g2,s2,p1,p2,m1,m2=best
        write(OUT1,p1); write(OUT2,p2)
        print('PASSING PLAN FOUND')
        print('reps',reps,'g1',g1,'s1',s1,'g2',g2,'s2',s2)
        print('b1', {k:m1[k] for k in sorted(TH['b1'])})
        print('b2', {k:m2[k] for k in sorted(TH['b2'])})
    else:
        print('NO PASSING PLAN FOUND IN TARGETED SEARCH')
        # Use best scalar combo discovered even if not fully passing, for debugging.
        # Keep current files but update with a reasonable default.
        reps=sorted(set(endpoint_reps(u1,6)+endpoint_reps(u2,2)))
        p1=build(reqs1,reps,96,32)
        p2=build(reqs2,reps,48,32)
        if len(set((x['shape']['seq_align'],x['shape']['heads_align'],x['shape']['hidden_align']) for x in p1+p2))<=MAX_SHAPES:
            write(OUT1,p1); write(OUT2,p2)
        print('fallback reps',reps)
        print('b1', {k:scalar_metrics(p1,map1,cm)[k] for k in sorted(TH['b1'])})
        print('b2', {k:scalar_metrics(p2,map2,cm)[k] for k in sorted(TH['b2'])})
    # Final verification through CostModel.plan_metrics
    for name,out,inp,mp in [('plan_b1.jsonl',OUT1,IN1,'b1'),('plan_b2.jsonl',OUT2,IN2,'b2')]:
        req_map={r['request_id']:r for r in load(inp)}
        plan=load(out)
        m=cm.plan_metrics(req_map, plan)
        v=validate(plan, req_map)
        print(name)
        print(' valid',v)
        print(' cost=%.6g pad_ratio=%.6f p95=%.6g seqtime=%.6g' % (m['cost'],m['pad_ratio'],m['p95_latency_ms'],m['sequential_timecost']))
        print(' pass', all(m[k]<=TH[mp][k] for k in TH[mp]))
        print(' batches', len(set(p['batch_id'] for p in plan)), 'shapes', len(set((p['shape']['seq_align'],p['shape']['heads_align'],p['shape']['hidden_align']) for p in plan)))
